oxy_webhelp_navlinks = {"create_rubrik_nas_cloud_direct_reports-d30753e54057":{"topics":[{"title":"<span class=\"ph\">NAS CD<\/span> Protection report","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Protection Report shows the protection status of <span class=\"ph\">NAS CD<\/span> on the Reports page. You can use this report to check the health of a         backup for data integrity and safety.<\/p>","href":"saas\/nascd_protection_report.html","attributes":{"data-id":"nascd_protection_report"},"menu":{"hasChildren":false},"tocID":"nascd_protection_report-d30753e54076","next":"nascd_protection_report-d30753e54076"},{"title":"<span class=\"ph\">NAS CD<\/span> Object Capacity report","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Object Capacity report provides details about the size         of a NAS Share and the storage space used to back up the NAS Share. You can use the <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Object Capacity report for insights on your storage consumption         for effective resource management and future planning.<\/p>","href":"saas\/nascd_object_capacity_report.html","attributes":{"data-id":"nascd_object_capacity_report"},"menu":{"hasChildren":false},"tocID":"nascd_object_capacity_report-d30753e54126","next":"nascd_object_capacity_report-d30753e54126"},{"title":"<span class=\"ph\">NAS CD<\/span> Object Capacity Over Time report","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Object Capacity Over Time report provides details about         the size of a NAS Share and the storage space used to back up the NAS Share over a period of         time. You can use the <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Object Capacity Over Time report for         insights on your storage consumption for effective resource management and future         planning.<\/p>","href":"saas\/nascd_object_capacity_over_time_report.html","attributes":{"data-id":"nascd_object_capacity_over_time_report"},"menu":{"hasChildren":false},"tocID":"nascd_object_capacity_over_time_report-d30753e54165","next":"nascd_object_capacity_over_time_report-d30753e54165"},{"title":"<span class=\"ph\">NAS CD<\/span> Compliance report","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Rubrik NAS Cloud Direct<\/span> Compliance report provides information about the         compliance status of <span class=\"ph\">NAS CD<\/span> objects. By using this report, you can determine         whether the snapshots taken for an object are in compliance with the policy schedule         associated with the object.<\/p>","href":"saas\/nascd_compliance_report.html","attributes":{"data-id":"nascd_compliance_report"},"menu":{"hasChildren":false},"tocID":"nascd_compliance_report-d30753e54201","next":"nascd_compliance_report-d30753e54201"},{"title":"<span class=\"ph\">NAS CD<\/span> report details","shortdesc":"<p class=\"shortdesc\">Information about the details you can view in the <span class=\"ph\">Rubrik NAS Cloud Direct<\/span>         Protection, Object Capacity, Object Capacity Over Time, and Compliance reports.<\/p>","href":"saas\/nascd_report_details.html","attributes":{"data-id":"nascd_report_details"},"menu":{"hasChildren":false},"tocID":"nascd_report_details-d30753e54240","topics":[]},{"title":"<span class=\"ph\">NAS CD<\/span> Usage report transition","shortdesc":"<p class=\"shortdesc\">Rubrik recommends that you transition from the <span class=\"ph\">NAS CD<\/span> Usage report to         the <span class=\"ph\">RSC<\/span> Object Capacity or Object Capacity Over Time reports because Rubrik         is deprecating the <span class=\"ph\">NAS CD<\/span> Usage report.<\/p>","href":"saas\/nas_cd_usage_report_transition.html","attributes":{"data-id":"nas_cd_usage_report_transition"},"menu":{"hasChildren":false},"tocID":"nas_cd_usage_report_transition-d30753e54256","topics":[]}]}};